// Some portions generated by Claude Code
package org.eclipse.rdf4j.sail.lmdb;

import static org.assertj.core.api.Assertions.assertThat;

import java.io.File;
import java.util.ArrayList;
import java.util.HashMap;
import java.util.List;
import java.util.Map;

import org.eclipse.rdf4j.model.IRI;
import org.eclipse.rdf4j.model.ValueFactory;
import org.eclipse.rdf4j.query.BindingSet;
import org.eclipse.rdf4j.query.QueryResults;
import org.eclipse.rdf4j.repository.sail.SailRepository;
import org.eclipse.rdf4j.repository.sail.SailRepositoryConnection;
import org.eclipse.rdf4j.sail.lmdb.config.LmdbStoreConfig;
import org.junit.jupiter.api.AfterEach;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.junit.jupiter.api.io.TempDir;

/**
 * End-to-end coverage for the CSR adjacency cache through the full query stack: probes must adaptively build entries,
 * later queries must hit them, results must stay identical to generic evaluation, and committed writes must invalidate.
 */
public class LmdbCsrCacheQueryTest {

	private static final String EX = "http://example.com/";
	private static final String ENABLED_FLAG = "rdf4j.lmdb.csrCache.enabled";
	private static final String MIN_PROBES_FLAG = "rdf4j.lmdb.csrCache.minProbes";
	private static final String NATIVE_FLAG = "rdf4j.lmdb.nativeQueryEngine.enabled";
	private static final String PARALLEL_FLAG = "rdf4j.lmdb.parallel.enabled";

	@TempDir
	File dataDir;

	private SailRepository repository;
	private Map<String, String> previousProperties;

	@BeforeEach
	public void setUp() {
		previousProperties = new HashMap<>();
		for (String property : new String[] { ENABLED_FLAG, MIN_PROBES_FLAG, NATIVE_FLAG, PARALLEL_FLAG }) {
			previousProperties.put(property, System.getProperty(property));
		}
		System.setProperty(ENABLED_FLAG, "true");
		System.setProperty(MIN_PROBES_FLAG, "1");
		// keep the probe path sequential and deterministic for engagement assertions
		System.setProperty(PARALLEL_FLAG, "false");
		repository = new SailRepository(new LmdbStore(dataDir, new LmdbStoreConfig("spoc,posc")));
		try (SailRepositoryConnection connection = repository.getConnection()) {
			ValueFactory vf = connection.getValueFactory();
			IRI p1 = vf.createIRI(EX, "p1");
			IRI p2 = vf.createIRI(EX, "p2");
			connection.begin();
			for (int i = 0; i < 300; i++) {
				IRI subject = vf.createIRI(EX, "s" + i);
				IRI middle = vf.createIRI(EX, "m" + i);
				connection.add(subject, p1, middle);
				for (int branch = 0; branch < 2; branch++) {
					connection.add(middle, p2, vf.createIRI(EX, "v" + i + "-" + branch));
				}
			}
			connection.commit();
		}
		resetCounters();
	}

	@AfterEach
	public void tearDown() {
		try {
			if (repository != null) {
				repository.shutDown();
			}
		} finally {
			for (Map.Entry<String, String> entry : previousProperties.entrySet()) {
				if (entry.getValue() == null) {
					System.clearProperty(entry.getKey());
				} else {
					System.setProperty(entry.getKey(), entry.getValue());
				}
			}
		}
	}

	private static void resetCounters() {
		LmdbCsrAdjacencyCache.BUILDS.set(0);
		LmdbCsrAdjacencyCache.HITS.set(0);
		LmdbCsrAdjacencyCache.STALE_DROPS.set(0);
	}

	private String chain() {
		return "SELECT ?subject ?value WHERE { ?subject <" + EX + "p1> ?middle . ?middle <" + EX + "p2> ?value . }";
	}

	private List<String> rows(String query) {
		try (SailRepositoryConnection connection = repository.getConnection()) {
			ArrayList<String> rows = new ArrayList<>();
			for (BindingSet row : QueryResults.asList(connection.prepareTupleQuery(query).evaluate())) {
				rows.add(row.getValue("subject") + "|" + row.getValue("value"));
			}
			rows.sort(String::compareTo);
			return rows;
		}
	}

	private List<String> rowsWithProperty(String property, String value, String query) {
		String previous = System.getProperty(property);
		try {
			System.setProperty(property, value);
			return rows(query);
		} finally {
			if (previous == null) {
				System.clearProperty(property);
			} else {
				System.setProperty(property, previous);
			}
		}
	}

	@Test
	public void probeTrafficBuildsEntryAndLaterQueriesHitIt() {
		List<String> first = rows(chain());
		assertThat(first).hasSize(600);
		assertThat(LmdbCsrAdjacencyCache.BUILDS.get())
				.as("the first query's probe traffic (300 probes on p2, flushed on close) must build an entry")
				.isGreaterThanOrEqualTo(1L);

		long hitsBefore = LmdbCsrAdjacencyCache.HITS.get();
		List<String> second = rows(chain());
		assertThat(LmdbCsrAdjacencyCache.HITS.get())
				.as("the second query must serve probes from the cache")
				.isGreaterThan(hitsBefore);
		assertThat(second).isEqualTo(first)
				.isEqualTo(rowsWithProperty(NATIVE_FLAG, "false", chain()));
	}

	@Test
	public void committedWriteInvalidatesAndResultsStayFresh() {
		rows(chain());
		rows(chain());
		assertThat(LmdbCsrAdjacencyCache.BUILDS.get()).isGreaterThanOrEqualTo(1L);

		try (SailRepositoryConnection connection = repository.getConnection()) {
			ValueFactory vf = connection.getValueFactory();
			connection.begin();
			connection.add(vf.createIRI(EX, "m5"), vf.createIRI(EX, "p2"), vf.createIRI(EX, "freshValue"));
			connection.commit();
		}

		List<String> after = rows(chain());
		assertThat(after).hasSize(601)
				.isEqualTo(rowsWithProperty(NATIVE_FLAG, "false", chain()));
		assertThat(after).anySatisfy(row -> assertThat(row).contains("freshValue"));
	}

	@Test
	public void uncommittedWritesRemainVisibleToTheirConnection() {
		rows(chain());
		rows(chain()); // cache is hot now

		try (SailRepositoryConnection connection = repository.getConnection()) {
			ValueFactory vf = connection.getValueFactory();
			connection.begin();
			connection.add(vf.createIRI(EX, "m7"), vf.createIRI(EX, "p2"), vf.createIRI(EX, "uncommittedValue"));
			List<BindingSet> result = QueryResults.asList(connection.prepareTupleQuery(chain()).evaluate());
			assertThat(result).hasSize(601);
			assertThat(result)
					.anySatisfy(row -> assertThat(row.getValue("value").stringValue()).contains("uncommittedValue"));
			connection.rollback();
		}

		assertThat(rows(chain())).hasSize(600);
	}
}
